 }

 /// \Returns true if \p I is a candidate instruction for reduction vectorization.
+
+
+/// Recursively check if an instruction or its operands have srem with divisor 0.
+
+static bool hasUndefinedSRemRecursive(Value *V, int Depth = 0) {
+
+  if (Depth > 3) // Limit recursion depth
+
+    return false;
+
+  
+
+  if (auto *Inst = dyn_cast<Instruction>(V)) {
+
+    if (auto *SRem = dyn_cast<BinaryOperator>(Inst)) {
+
+      if (SRem->getOpcode() == Instruction::SRem) {
+
+        if (auto *Divisor = dyn_cast<ConstantInt>(SRem->getOperand(1))) {
+
+          if (Divisor->isZero()) {
+
+            return true;
+
+          }
+
+        }
+
+      }
+
+    }
+
+    
+
+    // Check all operands
+
+    for (Value *Op : Inst->operands()) {
+
+      if (hasUndefinedSRemRecursive(Op, Depth + 1))
+
+        return true;
+
+    }
+
+  }
+
+  return false;
+
+}
+
+
 static bool isReductionCandidate(Instruction *I) {
   bool IsSelect = match(I, m_Select(m_Value(), m_Value(), m_Value()));
   Value *B0 = nullptr, *B1 = nullptr;
+  if (hasUndefinedSRemRecursive(I))
+    return false;
   bool IsBinop = matchRdxBop(I, B0, B1);
   return IsBinop || IsSelect;
 }
